-- 1. Mettre à jour le nom de l'entreprise de l'employeur principal (id=1) de Val G
UPDATE employeurs SET nomEntreprise = 'Cameroon Travail', secteurActivite = 'Recrutement / RH' WHERE id = 1;

-- 2. Transférer les offres de l'employeur 120001 vers l'employeur 1 (Val G)
UPDATE offresEmploi SET employeurId = 1 WHERE employeurId = 120001;

-- 3. Supprimer les candidatures liées aux offres (elles seront recréées via les offres)
-- D'abord vérifier si les candidatures existent encore après la mise à jour des offres
-- (les candidatures sont liées à offreId, pas à employeurId, donc elles restent valides)

-- 4. Supprimer les entrées dupliquées de Val G (garder seulement id=1)
DELETE FROM employeurs WHERE userId = 1 AND id != 1;

-- 5. Supprimer l'employeur 120001 (Valéry Garrec blankcontact1@gmail.com) qui n'a plus d'offres
DELETE FROM employeurs WHERE id = 120001;

